SELECT
    "总计" AS orderNo,
    IFNULL(SUM(a.coin_from),0) AS coinFrom,
    IFNULL(SUM(a.coin_value),0) AS coinValue,
    IFNULL(SUM(a.coin_to),0) AS coinTo
FROM
    user_coin_record a
WHERE
a.site_code = #{vo.siteCode}

    AND a.created_time >= #{vo.coinRecordStartTime}


    AND a.created_time <= #{vo.coinRecordEndTime}


    AND a.order_no = #{vo.orderNo}


    AND a.currency = #{vo.currencyCode}


    AND a.user_account = #{vo.userAccount}


    AND a.account_status = #{vo.accountStatus}


    AND a.risk_control_level_id = #{vo.riskLevelId}


    AND a.vip_rank >= #{vo.minVipRank}


    AND a.vip_rank <= #{vo.maxVipRank}


    AND a.vip_grade_code >= #{vo.minVipGradeCode}


    AND a.vip_grade_code <= #{vo.maxVipGradeCode}


    AND a.business_coin_type = #{vo.businessCoinType}


    AND a.coin_type = #{vo.coinType}


    AND a.balance_type = #{vo.balanceType}


    AND a.business_coin_type IN

        #{value}



    AND a.coin_type IN

        #{value}




    AND a.coin_value >= #{vo.minCoinValue}


    AND a.coin_value <= #{vo.maxCoinValue}

SELECT tab.id, tab.userAccount, tab.orderNo, tab.dividendType, tab.dividendStatus, tab.currencyCode, tab.dividendAmount, tab.applyTime, tab.receiveTime FROM (
SELECT id, user_account AS userAccount, order_no as orderNo, 2 AS dividendType, (case when receive_status = 0 then 4 when receive_status = 1 then 1 when receive_status = 2 then 5 else 0 end) AS dividendStatus, currency_code AS currencyCode, activity_amount AS dividendAmount, created_time AS applyTime, receive_end_time as receiveTime FROM site_activity_order_record WHERE site_code = #{vo.siteCode}
AND super_agent_id in
#{value}
AND user_account = #{vo.userAccount}
AND receive_start_time BETWEEN #{vo.beginTime} AND #{vo.endTime}
UNION ALL SELECT id, user_account AS userAccount, order_id as orderNo, 1 AS dividendType, (case when receive_status = 0 AND expired_time < #{vo.systemTime} THEN 5 when receive_status = 0 then 4 when receive_status = 1 then 1 when receive_status = 2 then 5 else 3 end) AS dividendStatus, 'WTC' AS currencyCode, award_amount AS dividendAmount, created_time AS applyTime, expired_time as receiveTime FROM site_vip_award_record WHERE site_code = #{vo.siteCode}
AND agent_id in
#{value}
AND user_account = #{vo.userAccount}
AND record_start_time BETWEEN #{vo.beginTime} AND #{vo.endTime}
UNION ALL SELECT id, user_account AS userAccount, order_no as orderNo, 3 AS dividendType, (case when receive_status = 0 then 4 when receive_status = 1 then 1 when receive_status = 2 then 5 when receive_status = 3 then 3 else 3 end) AS dividendStatus, currency_code AS currencyCode, task_amount AS dividendAmount, created_time AS applyTime, receive_end_time as receiveTime FROM site_task_order_record WHERE site_code = #{vo.siteCode} and task_type = 'novice'
AND super_agent_id in
#{value}
AND user_account = #{vo.userAccount}
AND receive_start_time BETWEEN #{vo.beginTime} AND #{vo.endTime}
UNION ALL SELECT id, user_account AS userAccount, order_no as orderNo, 4 AS dividendType, (case when receive_status = 0 then 4 when receive_status = 1 then 1 when receive_status = 2 then 5 when receive_status = 3 then 3 else 3 end) AS dividendStatus, currency_code AS currencyCode, task_amount AS dividendAmount, created_time AS applyTime, receive_end_time as receiveTime FROM site_task_order_record WHERE site_code = #{vo.siteCode} and task_type = 'daily'
AND super_agent_id in
#{value}
AND user_account = #{vo.userAccount}
AND receive_start_time BETWEEN #{vo.beginTime} AND #{vo.endTime}
UNION ALL SELECT id, user_account AS userAccount, order_no as orderNo, 5 AS dividendType, (case when receive_status = 0 then 4 when receive_status = 1 then 1 when receive_status = 2 then 5 when receive_status = 3 then 3 else 3 end) AS dividendStatus, currency_code AS currencyCode, task_amount AS dividendAmount, created_time AS applyTime, receive_end_time as receiveTime FROM site_task_order_record WHERE site_code = #{vo.siteCode} and task_type = 'week'
AND super_agent_id in
#{value}
AND user_account = #{vo.userAccount}
AND receive_start_time BETWEEN #{vo.beginTime} AND #{vo.endTime}
UNION ALL SELECT id, user_account AS userAccount, order_no as orderNo, 7 AS dividendType, (case when open_status = 0 then 4 when open_status = 1 then 1 else 3 end) AS dividendStatus, 'WTC' AS currencyCode, reward_amount AS dividendAmount, created_time AS applyTime, open_time as receiveTime
FROM medal_reward_record WHERE site_code = #{vo.siteCode}
AND super_agent_id in
#{value}
AND user_account = #{vo.userAccount}
AND open_status = 1 AND complete_time BETWEEN #{vo.beginTime} AND #{vo.endTime}
UNION ALL SELECT id, user_account AS userAccount, order_no as orderNo, 6 AS dividendType, (case when lock_status = 0 then 4 when lock_status = 1 then 1 else 3 end) AS dividendStatus, 'WTC' AS currencyCode, reward_amount AS dividendAmount, created_time AS applyTime, unlock_time as receiveTime FROM medal_acquire_record WHERE site_code = #{vo.siteCode}
AND super_agent_id in
#{value}
AND user_account = #{vo.userAccount}
AND complete_time BETWEEN #{vo.beginTime} AND #{vo.endTime}
UNION ALL select t.id as id, u.user_account as userAccount, t.order_no as orderNo, 8 AS dividendType, ( CASE WHEN t.open_status = 0 THEN 4 WHEN open_status = 1 THEN 1 WHEN open_status = 2 THEN 5 ELSE 0 END ) AS dividendStatus, 'WTC' AS currencyCode, t.reward_amount AS dividendAmount, t.created_time AS applyTime, t.invalid_time AS receiveTime from site_rebate_reward_record t join user_info u on t.user_id =u.user_id and u.site_code = #{vo.siteCode} WHERE 1 = 1
AND t.super_agent_id in
#{value}
AND u.user_account = #{vo.userAccount}
AND t.created_time BETWEEN #{vo.beginTime} AND #{vo.endTime} ) tab
and tab.dividendType = #{vo.dividendType}
and tab.dividendStatus = #{vo.dividendStatus}
ORDER BY dividendStatus ASC, applyTime DESC

SELECT count(1) FROM ( SELECT user_id FROM user_coin_record a where 1 = 1
AND a.user_id IN
#{value}
AND a.coin_type IN
#{value}
GROUP BY a.user_id )t1

SELECT order_no FROM user_coin_record a where 1 = 1
AND a.order_no IN
#{value}

select a.site_code as siteCode, a.user_id as userId, a.user_account as userAccount, a.agent_id as agentId, a.agent_name as superAgentAccount, a.currency as mainCurrency, SUM(case when(a.business_coin_type) in( '3','4','8','10' )then a.coin_to-a.coin_from end) as alreadyUseAmount, SUM(case when(a.business_coin_type) ='10' then a.coin_to-a.coin_from end) as rebateAmount, sum(case when(a.business_coin_type) = '9' then a.coin_to-a.coin_from end) as adjustAmount, sum(case when(a.business_coin_type) = '11' then a.coin_to-a.coin_from end) as riskAmount, ANY_VALUE(b.account_type) AS accountType from user_coin_record a LEFT JOIN user_info b on a.user_id=b.user_id where a.created_time >= #{vo.startTime} and a.created_time <= #{vo.endTime}
and a.site_code = #{vo.siteCode}
AND a.business_coin_type IN
#{value}
group by a.site_code,a.user_id,a.user_account,a.currency,a.agent_id,a.agent_name order by a.site_code,a.user_id,a.user_account,a.currency,a.agent_id,a.agent_name
